import os
import boto3
from botocore.exceptions import ClientError, NoCredentialsError


def get_s3_client():
    """
    Create an S3 client using credentials from environment variables
    or AWS configuration (e.g., ~/.aws/credentials, IAM role, etc.).
    
    Before running, set the following environment variables:
        export AWS_ACCESS_KEY_ID=<your-access-key>
        export AWS_SECRET_ACCESS_KEY=<your-secret-key>
        export AWS_DEFAULT_REGION=us-east-1  # optional
    
    Alternatively, configure credentials via:
        - AWS CLI: `aws configure`
        - IAM instance role (if running on EC2/Lambda)
        - A secrets manager such as AWS Secrets Manager
    """
    aws_access_key = os.environ.get("AWS_ACCESS_KEY_ID")
    aws_secret_key = os.environ.get("AWS_SECRET_ACCESS_KEY")
    aws_region = os.environ.get("AWS_DEFAULT_REGION", "us-east-1")

    if not aws_access_key or not aws_secret_key:
        raise EnvironmentError(
            "AWS credentials not found. Please set the environment variables "
            "AWS_ACCESS_KEY_ID and AWS_SECRET_ACCESS_KEY before running this script.\n"
            "Example:\n"
            "  export AWS_ACCESS_KEY_ID=<your-access-key>\n"
            "  export AWS_SECRET_ACCESS_KEY=<your-secret-key>\n"
        )

    client = boto3.client(
        "s3",
        aws_access_key_id=aws_access_key,
        aws_secret_access_key=aws_secret_key,
        region_name=aws_region,
    )
    return client


def list_bucket_files(bucket_name):
    """List all files in the specified S3 bucket."""
    try:
        s3_client = get_s3_client()
        print(f"Connecting to S3 bucket: {bucket_name}\n")

        paginator = s3_client.get_paginator("list_objects_v2")
        page_iterator = paginator.paginate(Bucket=bucket_name)

        file_count = 0
        for page in page_iterator:
            contents = page.get("Contents", [])
            for obj in contents:
                file_count += 1
                print(
                    f"  {file_count:4d}. {obj['Key']:<60s}  "
                    f"Size: {obj['Size']:>10,} bytes  "
                    f"Last Modified: {obj['LastModified']}"
                )

        if file_count == 0:
            print("  (No files found in this bucket)")
        else:
            print(f"\nTotal files: {file_count}")

    except NoCredentialsError:
        print("ERROR: AWS credentials were not found or are invalid.")
        print("Please set AWS_ACCESS_KEY_ID and AWS_SECRET_ACCESS_KEY environment variables.")
    except ClientError as e:
        error_code = e.response["Error"]["Code"]
        error_msg = e.response["Error"]["Message"]
        print(f"ERROR: AWS S3 returned an error — [{error_code}] {error_msg}")
    except EnvironmentError as e:
        print(f"ERROR: {e}")


if __name__ == "__main__":
    BUCKET_NAME = os.environ.get("S3_BUCKET_NAME", "demo-bucket")
    list_bucket_files(BUCKET_NAME)